//in:&IsPagar13,in:&Tipo13,in:&IsPagarFerias,in:&TipoFer,in:&IsCobrarContSindical,in:&IsAbono,in:&AbonoVlr,in:&AbonoDtaReg

&DtaIni = YMDtoD(&FPagAno,&FPagMes,1)
&DtaFin = eom(&DtaIni)

insertRotinaAtualizarOperacoesFolha.Call(&EmpCod,Status_SimNao.Nao)

For each Order EmpCod, PesCod 
	Where EmpCod = &EmpCod
	Where PesIsFun = True when &PesCod = 0
	Where PesSts = Status_AtivoInativo.ATIVO when &PesCod = 0
	Where PesSalTip = 'M' or PesSalTip.IsNull() or PesSalTip.IsEmpty() when &PesCod = 0
	Where PesCod = &PesCod when &PesCod <> 0
	Where PesFunFilCod = &PesFunFilCod when not &PesFunFilCod.IsEmpty() 

	if PesSalTip.IsEmpty() or PesSalTip.IsNull()
		prcAtualizaMensalista.Call(EmpCod, 0)
	Endif
	&FPagCod = 0
	prcAlgumLancamentoPagamentoFolha.Call(EmpCod, PesCod, &FPagAno, &FPagMes, &FPagCod, &IstemAlgumLancamento)

	if &FPagCod = 0 and PesSalTotRec > 0

		&PesIsSocPro = PesIsSocPro
		&PesSalFix = PesSalFix
		&PesVlrOutAcr = PesVlrOutAcr
		&PesVlrBon = PesVlrBon
		&PesVlrSalTotCon = PesVlrSalTotCon		
		&PesPerInsVlr =  PesPerInsVlr
		&PesPerPerVlr = PesPerPerVlr
		&PesVlrRef = PesVlrRef
		&PesVlrTrp = PesVlrTrp

		&FPagIsErro = false
		&sdtPagamentosFolhaContas.Clear()
		&sdtItensFolha.Clear()
		&SdtMovimentoItem.Clear()
		&sdtPagamentoFolhaAdiantamentos.Clear()
		&TotalLancamento = 0
		&FPagLcfCod = 0
		&TotalAdiantamentos = 0		
		do 'getOperacoesFolha'

		if &sdtItensFolha.Count > 0

			if &isAdiantamentos = true
				&TotalAdiantamentos = 0
				RetornaAdiantamentosPagamentoFolha.Call(&EmpCod, 0, &FPagAno, &FPagMes, PesCod, &sdtPagamentoFolhaAdiantamentos, &SdtMovimentoItem)

				for &SdtMovimentoItemItem in &SdtMovimentoItem					
					&sdtPagamentoFolhaAdiantamentosItem = new()
					&sdtPagamentoFolhaAdiantamentosItem.FPagAdiMovCod = &SdtMovimentoItemItem.MovCod
					&sdtPagamentoFolhaAdiantamentosItem.FPagAdiMovItmCod = &SdtMovimentoItemItem.MovItmCod
					&sdtPagamentoFolhaAdiantamentosItem.FPagAdiMovVlr = &SdtMovimentoItemItem.MovItmVlr
					&TotalAdiantamentos += &SdtMovimentoItemItem.MovItmVlr
					&sdtPagamentoFolhaAdiantamentos.Add(&sdtPagamentoFolhaAdiantamentosItem)
				EndFor				

				if &TotalAdiantamentos > 0
					&FPagLcfCod = 95 //Adiantamentos
					do 'getOperacoesFolha'
				Endif
			Endif

			//Contas
			&FPagCtaTip = PesTipFol
			&sdtPagamentosFolhaContas.Clear()
			&sdtPagamentosFolhaContasItem = new()
			&sdtPagamentosFolhaContasItem.FPagCtaTip = PesTipFol
			&sdtPagamentosFolhaContasItem.FPagCtaBanCod = PesCtaBanCod
			&sdtPagamentosFolhaContasItem.FPagCtaVlr = &TotalLancamento
			&sdtPagamentosFolhaContasItem.FPagCtaNroDoc = &FPagCtaNroDoc
			&sdtPagamentosFolhaContas.Add(&sdtPagamentosFolhaContasItem)

			do 'validaLancamento'
			prcGravaPagamentoFolha.Call(&EmpCod, 0, TipoPagamentoFolha.FolhaMensal, PesCod, &FPagAno, &FPagMes, &FPagIsErro, &FPagCod)
			prcGravaPagamentoFolhaItem.call(&EmpCod, &FPagCod, &sdtItensFolha, &sdtPagamentosFolhaContas, &sdtPagamentoFolhaAdiantamentos)
		Endif

	EndIf
EndFor

Sub 'validaLancamento'

	For &sdtItensFolhaItem in &sdtItensFolha
		Do CAse
			CAse &sdtItensFolhaItem.PlanCod.IsEmpty() and &sdtItensFolhaItem.LcfCreDeb = 'C' and (&sdtItensFolhaItem.FPagLcfCod = 1 or &sdtItensFolhaItem.FPagLcfCod = 22 or &sdtItensFolhaItem.FPagLcfCod = 23)		
				//Msg('Existe um erro na operação: '+&sdtItensFolhaItem.FPagLcfCod.ToString() +', as operações do tipo Crédito precisam conter plano de contas!')
				&FPagIsErro = true
				exit
			Case &sdtItensFolhaItem.FPagItemVlr <= 0
				//Msg('Existe um erro na operação: '+&sdtItensFolhaItem.FPagLcfCod.ToString() +', Valor informado não pode ser menor ou igual a zero!')
				&FPagIsErro = true
				exit
		EndCAse	
	EndFor

	Do CAse
		Case &FPagCtaTip = TipoFolha.ChequePropio
			&FPagIsErro = true
	EndCAse

	prcValidaPAgamentoAdiantamentos.Call(&EmpCod, 0, &sdtPagamentoFolhaAdiantamentos,&IsErroAdiantamentos, &MensagemAdiantamentos)

	Do CAse
		CAse &TotalLancamento < 0
			//Msg('Atenção Total dos lançamentos não pode ser negativo.')
			&FPagIsErro = true

		Case &FPagIsErro = true
			//parou o processo

		case &IsErroAdiantamentos= true
			//msg(&MensagemAdiantamentos)
			&FPagIsErro = true

		case &sdtItensFolha.Count = 0
			//msg('ATENÇÃO! Necessário ter no mínimo um item para efetuar o lançamento!')
			&FPagIsErro = true

		//CAse &TotalLancamento <> &TotalPagamento
			//msg('Total de Lançamentos a Pagar diferente do total de Pagamentos informados!')
			//&FPagIsErro = true

		//CAse &IsPagamentoMultiplo = true and &sdtPagamentosFolhaContas.Count = 1
			//msg('Selecionado opção pagamento múltiplo e não informado mais de uma conta, favor alterar para pagamento Único!')
	EndCAse
EndSub


Sub 'getOperacoesFolha'

	For Each ORder EmpCod, LcfCod
		Where EmpCod = &EmpCod
		Where LcfCod = &FPagLcfCod when not &FPagLcfCod.IsEmpty()
		Where LcfVlrPad <> 'X' and not LcfVlrPad.IsEmpty() and not LcfVlrPad.IsNull() when &FPagLcfCod.IsEmpty()

		&LcfCod = LcfCod
		&FPagItemVlr = 0
		&LcfCreDeb = LcfCreDeb

		Do case
			Case LcfCod = 1 and &PesIsSocPro =  true
				&FPagItemVlr = 0
			CAse LcfCod = 95
				&FPagItemVlr = &TotalAdiantamentos
				&TotalAdiantamentos = 0
			case ((LcfCod = 1 or LcfCod = 22) and (LcfVlrPad.IsEmpty() or LcfVlrPad.IsNull() or LcfVlrPad = 'X')) or LcfVlrPad = 'A' //Salário Fixo
				&FPagItemVlr = &PesSalFix
				&PesSalFix = 0
				&PesVlrSalTotCon = 0
			Case LcfVlrPad = 'B' //Salário TOTAL
				&FPagItemVlr = &PesVlrSalTotCon
				&PesSalFix = 0
				&PesVlrSalTotCon = 0
			Case LcfVlrPad = 'C' //BONIFICACAO
				if &IsBonificacao = true
					&FPagItemVlr = &PesVlrBon
				Endif
				&PesVlrBon = 0
			Case LcfVlrPad = 'D' //OUTROS ACRESC.
				if &IsOutrosAcrescimos= true
					&FPagItemVlr = &PesVlrOutAcr
				Endif		
				&PesVlrOutAcr = 0
			Case LcfVlrPad = 'E' //PERICULOSIDADE
				If &IsPericulosidade = true
					&FPagItemVlr = &PesPerPerVlr
				Endif
				&PesPerPerVlr = 0
			Case LcfVlrPad = 'F' //INSALUBRIDADE
				if &IsInsalubridade
					&FPagItemVlr = &PesPerInsVlr
				Endif
				&PesPerInsVlr = 0
			Case LcfVlrPad = 'G' //VALE TRANSPORTE
				if &IsValeTransporte= true
					&FPagItemVlr = &PesVlrTrp
				Endif
				&PesVlrTrp = 0
			Case LcfVlrPad = 'H' //VALE REFEICAO
				If &IsValeAlimentacao
				&FPagItemVlr = &PesVlrRef
				Endif
				&PesVlrRef = 0
		EndCase	

		if &FPagItemVlr > 0
			do 'addsdtItens'
		Endif

	EndFor
EndSub


Sub 'addsdtItens'	
	&IsAchou = false
	For &sdtItensFolhaItem in &sdtItensFolha
		if &sdtItensFolhaItem.FPagLcfCod = &LcfCod
			&IsAchou = true
			&sdtItensFolhaItem.FPagItemVlr = &FPagItemVlr
			//Exit tirei para poder somar tudo.
		EndIf

		if &sdtItensFolhaItem.LcfCreDeb = 'C'
			&TotalLancamento += &sdtItensFolhaItem.FPagItemVlr
		Else
			&TotalLancamento -= &sdtItensFolhaItem.FPagItemVlr
		Endif
	EndFor	

	if &IsAchou = false
		&sdtItensFolhaItem = new()
		&sdtItensFolhaItem.FPagLcfCod = &LcfCod
		&sdtItensFolhaItem.LcfCreDeb = &LcfCreDeb
		&sdtItensFolhaItem.FPagItemVlr = &FPagItemVlr
		&sdtItensFolha.Add(&sdtItensFolhaItem)

		if &LcfCreDeb = 'C'
			&TotalLancamento += &FPagItemVlr
		Else
			&TotalLancamento -= &FPagItemVlr
		Endif
	Endif
EndSub

